={
  "messages": [
    {"role": "system", "content": "Du erstellst einen wöchentlichen KI-Support-Report auf Deutsch. Bewerte die Zahlen und gib 2-3 konkrete Handlungsempfehlungen."},
    {"role": "user", "content": "KPI-Daten der letzten Woche:\n{{ JSON.stringify($('DB: Weekly KPIs').item.json, null, 2) }}\n\nOffene Tickets: {{ $('Zammad: Open Ticket Count').item.json.total_count }}\n\nErstelle einen knappen Report (max 300 Wörter)."}
  ],
  "temperature": 0.4,
  "max_tokens": 600
}

={
  "message": {
    "subject": "📊 AI Ticketing Buddy — Wochenbericht {{ new Date().toLocaleDateString('de-DE') }}",
    "body": {
      "contentType": "Text",
      "content": "{{ $('Azure OpenAI: Generate Report Summary').item.json.choices[0].message.content }}\n\n---\nKPIs:\n- Tickets klassifiziert: {{ $('DB: Weekly KPIs').item.json.tickets_classified }}\n- Drafts erstellt: {{ $('DB: Weekly KPIs').item.json.drafts_created }}\n- Ø Bewertung: {{ $('DB: Weekly KPIs').item.json.avg_rating?.toFixed(1) || 'k.A.' }}/5\n- Eskalationen: {{ $('DB: Weekly KPIs').item.json.escalations }}\n- Workflow Fehler: {{ $('DB: Weekly KPIs').item.json.workflow_errors }}"
    },
    "toRecipients": [{"emailAddress": {"address": "{{ $env.TEAMLEAD_EMAIL }}"}}]
  }
}
